import React, { useState, useEffect } from 'react';
import axios from 'axios';

const AdminPanel = () => {
  const [activeTab, setActiveTab] = useState('create'); 
  const [postType, setPostType] = useState('blog'); 
  const [category, setCategory] = useState('electronics'); // Default Category
  const [formData, setFormData] = useState({ title: '', description: '', loc: '', salary: '', type: 'On-site' });
  const [file, setFile] = useState(null);
  const [items, setItems] = useState([]); 

  const [isEditing, setIsEditing] = useState(false);
  const [editData, setEditData] = useState(null);

  const fetchItems = async () => {
    try {
      const url = postType === 'job' 
        ? 'http://localhost:5001/api/jobs' 
        : `http://localhost:5001/api/blog/${category}`;
      const res = await axios.get(url);
      setItems(res.data);
    } catch (err) { console.error(err); }
  };

  useEffect(() => {
    if (activeTab === 'manage') fetchItems();
  }, [activeTab, postType, category]);

  const handleUpdate = async (e) => {
    e.preventDefault();
    try {
      const endpoint = postType === 'job' ? 'jobs' : 'blog';
      await axios.patch(`http://localhost:5001/api/admin/${endpoint}/${editData._id}`, editData);
      alert("Updated Successfully!");
      setIsEditing(false);
      fetchItems();
    } catch (err) { alert("Update failed"); }
  };

  const handleDelete = async (id) => {
    if (window.confirm("Kyan aap ise delete karna chahte hain?")) {
      try {
        const endpoint = postType === 'job' ? 'jobs' : 'blog';
        await axios.delete(`http://localhost:5001/api/admin/${endpoint}/${id}`);
        fetchItems();
        alert("Deleted!");
      } catch (err) { alert("Delete Failed"); }
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      let response;
      if (postType === 'job') {
        response = await axios.post('http://localhost:5001/api/admin/jobs', formData);
      } else {
        const data = new FormData();
        data.append('category', category); // Category yahan se jayegi
        data.append('title', formData.title);
        data.append('description', formData.description);
        if (file) data.append('image', file);
        response = await axios.post('http://localhost:5001/api/admin/blog', data);
      }
      if (response.status === 201) {
        alert("Published!");
        setFormData({ title: '', description: '', loc: '', salary: '', type: 'On-site' });
        setFile(null);
        e.target.reset();
      }
    } catch (err) { alert("Error publishing"); }
  };

  return (
    <div className="flex min-h-screen bg-gray-50 pt-10">
      {/* SIDEBAR */}
      <div className="w-80 bg-black text-white p-8 fixed h-full">
        <h2 className="text-2xl font-black text-orange-500 mb-10 tracking-tighter">HUDSON ADMIN</h2>
        <div className="space-y-2">
          <button onClick={() => setActiveTab('create')} className={`w-full text-left p-4 rounded-2xl font-bold transition-all ${activeTab === 'create' ? 'bg-orange-600 shadow-lg shadow-orange-900/20' : 'text-gray-400 hover:text-white'}`}>➕ Create New</button>
          <button onClick={() => setActiveTab('manage')} className={`w-full text-left p-4 rounded-2xl font-bold transition-all ${activeTab === 'manage' ? 'bg-orange-600 shadow-lg shadow-orange-900/20' : 'text-gray-400 hover:text-white'}`}>⚙️ Manage All</button>
        </div>

        <div className="mt-10 border-t border-gray-800 pt-6 space-y-4">
           <div className="flex bg-gray-900 p-1 rounded-xl">
             <button onClick={() => setPostType('job')} className={`flex-1 py-2 rounded-lg text-xs font-black uppercase tracking-widest ${postType === 'job' ? 'bg-white text-black' : 'text-gray-500'}`}>Jobs</button>
             <button onClick={() => setPostType('blog')} className={`flex-1 py-2 rounded-lg text-xs font-black uppercase tracking-widest ${postType === 'blog' ? 'bg-white text-black' : 'text-gray-500'}`}>Blogs</button>
           </div>

           {/* BLOG CATEGORY SELECTOR (FOR BOTH CREATE & MANAGE) */}
           {postType === 'blog' && (
             <div className="space-y-2">
               <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-2">Select Category</p>
               <select 
                 value={category} 
                 onChange={(e) => setCategory(e.target.value)}
                 className="w-full bg-gray-800 text-white p-3 rounded-xl text-sm outline-none border border-gray-700"
               >
                 <option value="electronics">Electronics</option>
                 <option value="interior">Interior</option>
                 <option value="fashion">Fashion</option>
               </select>
             </div>
           )}
        </div>
      </div>

      {/* MAIN CONTENT */}
      <div className="flex-1 ml-80 p-12">
        {activeTab === 'create' ? (
          <div className="max-w-3xl bg-white rounded-[3rem] p-12 shadow-sm border border-gray-100">
            <h1 className="text-4xl font-black mb-10 italic">Add {postType === 'blog' ? 'Blog Post' : 'Job Opening'}</h1>
            <form onSubmit={handleSubmit} className="space-y-4">
              <input required className="w-full p-4 bg-gray-50 rounded-xl font-bold border border-transparent focus:border-orange-500 outline-none" placeholder="Title" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} />

              {postType === 'blog' ? (
                <>
                  <textarea rows="6" className="w-full p-4 bg-gray-50 rounded-xl font-bold border border-transparent focus:border-orange-500 outline-none" placeholder="Blog Description..." value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
                  <div className="p-6 border-2 border-dashed border-gray-200 rounded-2xl bg-gray-50/50">
                    <p className="text-[10px] font-black text-gray-400 uppercase mb-2 tracking-widest">Featured Image</p>
                    <input type="file" onChange={(e) => setFile(e.target.files[0])} className="text-sm font-bold" />
                  </div>
                </>
              ) : (
                <div className="grid grid-cols-2 gap-4">
                  <input className="p-4 bg-gray-50 rounded-xl font-bold border border-transparent focus:border-orange-500 outline-none" placeholder="Location (e.g. Noida)" value={formData.loc} onChange={e => setFormData({...formData, loc: e.target.value})} />
                  <input className="p-4 bg-gray-50 rounded-xl font-bold border border-transparent focus:border-orange-500 outline-none" placeholder="Salary (e.g. 5-8 LPA)" value={formData.salary} onChange={e => setFormData({...formData, salary: e.target.value})} />
                </div>
              )}
              <button className="w-full bg-black text-white py-5 rounded-2xl font-black text-lg hover:bg-orange-600 transition-all shadow-xl shadow-gray-200">PUBLISH CONTENT</button>
            </form>
          </div>
        ) : (
          <div className="max-w-4xl bg-white rounded-[3rem] p-12 shadow-sm border border-gray-100">
            <h1 className="text-4xl font-black mb-10 italic text-gray-900">Manage {postType}s</h1>
            <div className="space-y-4">
              {items.map(item => (
                <div key={item._id} className="flex items-center justify-between p-6 bg-gray-50 rounded-[2rem] border border-gray-100 hover:bg-white hover:shadow-lg transition-all duration-300">
                  <div>
                    <h3 className="font-black text-xl text-gray-800">{item.title}</h3>
                    <p className="text-orange-500 text-[10px] font-black uppercase tracking-widest mt-1">{item.loc || item.category}</p>
                  </div>
                  <div className="flex gap-2">
                    <button onClick={() => { setEditData(item); setIsEditing(true); }} className="bg-white border border-gray-200 text-blue-600 px-6 py-2 rounded-xl font-black text-[10px] hover:bg-blue-600 hover:text-white transition-all">EDIT</button>
                    <button onClick={() => handleDelete(item._id)} className="bg-white border border-gray-200 text-red-500 px-6 py-2 rounded-xl font-black text-[10px] hover:bg-red-600 hover:text-white transition-all uppercase">Delete</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* --- EDIT MODAL --- */}
      {isEditing && editData && (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-md z-[100] flex items-center justify-center p-6">
          <div className="bg-white w-full max-w-xl rounded-[3rem] p-10 relative shadow-2xl">
            <button onClick={() => setIsEditing(false)} className="absolute top-8 right-8 text-2xl font-light hover:text-orange-600 transition-colors">✕</button>
            <h2 className="text-3xl font-black mb-8 italic">Edit {postType}</h2>
            <form onSubmit={handleUpdate} className="space-y-4">
              <input required className="w-full p-4 bg-gray-50 rounded-xl font-bold border outline-none" value={editData.title} onChange={e => setEditData({...editData, title: e.target.value})} />
              {postType === 'blog' ? (
                <textarea rows="5" className="w-full p-4 bg-gray-50 rounded-xl font-bold border outline-none" value={editData.description} onChange={e => setEditData({...editData, description: e.target.value})} />
              ) : (
                <div className="grid grid-cols-2 gap-4">
                  <input className="p-4 bg-gray-50 rounded-xl font-bold border outline-none" value={editData.loc} onChange={e => setEditData({...editData, loc: e.target.value})} />
                  <input className="p-4 bg-gray-50 rounded-xl font-bold border outline-none" value={editData.salary} onChange={e => setEditData({...editData, salary: e.target.value})} />
                </div>
              )}
              <button type="submit" className="w-full bg-orange-600 text-white py-5 rounded-2xl font-black">UPDATE NOW</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;
